    await sendTelegramReport(`${cmd === "/done" ? "\u2705" : "\u2716\uFE0F"} \`${match.id.slice(-9)}\` ${match.title}
\u2192 ${newStatus === "done" ? "\uC644\uB8CC" : "\uCDE8\uC18C"} \uCC98\uB9AC\uB428.`);
    return;
