function _extractFirstJsonObject(raw) {
  if (!raw) return null;
  const stripped = raw.replace(/```[a-zA-Z]*\n?|```/g, "");
  const candidates = [];
  let i = 0;
  while (i < stripped.length) {
    const start = stripped.indexOf("{", i);
    if (start < 0) break;
    let depth = 0;
    let inStr = false;
    let esc = false;
    let endIdx = -1;
    for (let j = start; j < stripped.length; j++) {
      const ch = stripped[j];
      if (esc) {
        esc = false;
        continue;
      }
      if (ch === "\\") {
        esc = true;
        continue;
      }
      if (ch === '"') {
        inStr = !inStr;
        continue;
      }
      if (inStr) continue;
      if (ch === "{") depth++;
      else if (ch === "}") {
        depth--;
        if (depth === 0) {
          endIdx = j;
          break;
        }
      }
    }
    if (endIdx < 0) break;
    try {
      const obj = JSON.parse(stripped.slice(start, endIdx + 1));
      if (obj && typeof obj === "object") candidates.push(obj);
    } catch {
    }
    i = endIdx + 1;
  }
  if (candidates.length === 0) return null;
  const withMode = candidates.find((c) => typeof c.mode === "string");
  return withMode || candidates[0];
}
