function appendConversationLog(entry) {
  try {
    const convDir = getConversationsDir();
    fs.mkdirSync(convDir, { recursive: true });
    const today = (/* @__PURE__ */ new Date()).toISOString().slice(0, 10);
    const dayFile = path.join(convDir, `${today}.md`);
    if (!fs.existsSync(dayFile)) {
      fs.writeFileSync(dayFile, `# \u{1F4DC} ${today} \uD68C\uC0AC \uB300\uD654\uB85D

_\uBAA8\uB4E0 \uBA85\uB839\xB7\uBD84\uBC30\xB7\uC0B0\uCD9C\uBB3C\xB7\uB300\uD654\uAC00 \uC2DC\uAC04\uC21C\uC73C\uB85C \uB204\uC801\uB429\uB2C8\uB2E4. \uB450\uB1CC\uAC00 \uC790\uB3D9 \uC778\uB371\uC2F1\xB7\uB3D9\uAE30\uD654\uD569\uB2C8\uB2E4._
`);
    }
    const ts = (/* @__PURE__ */ new Date()).toLocaleTimeString("ko-KR", { hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false });
    const emoji = entry.emoji || "\u{1F5E8}\uFE0F";
    const sectionLine = entry.section ? ` \xB7 _${entry.section}_` : "";
    const block = `
## [${ts}] ${emoji} **${entry.speaker}**${sectionLine}

${entry.body}
`;
    fs.appendFileSync(dayFile, block);
  } catch {
  }
}
function readRecentConversations(maxChars = 2500) {
  try {
    const convDir = getConversationsDir();
    if (!fs.existsSync(convDir)) return "";
    const today = (/* @__PURE__ */ new Date()).toISOString().slice(0, 10);
    const yesterday = new Date(Date.now() - 864e5).toISOString().slice(0, 10);
    let combined = "";
    for (const day of [yesterday, today]) {
      const f = path.join(convDir, `${day}.md`);
      if (fs.existsSync(f)) {
        try {
          combined += fs.readFileSync(f, "utf-8");
        } catch {
        }
      }
    }
    if (!combined) return "";
    const tail = combined.slice(-maxChars);
    return `

[\uCD5C\uADFC \uD68C\uC0AC \uB300\uD654 \uC694\uC57D (\uCC38\uACE0\uC6A9)]
${tail}
`;
  } catch {
    return "";
  }
}
function makeSessionDir() {
  const ts = (/* @__PURE__ */ new Date()).toISOString().replace(/[:.]/g, "-").slice(0, 16);
  const dir = path.join(getCompanyDir(), "sessions", ts);
  fs.mkdirSync(dir, { recursive: true });
  return dir;
}
