  // --------------------------------------------------------
  // Fetch installed Ollama models
  // --------------------------------------------------------
  async _sendModels() {
    if (!this._view) {
      return;
    }
    const { ollamaBase, defaultModel } = getConfig();
    try {
      const isLMStudio = ollamaBase.includes("1234") || ollamaBase.includes("v1");
      let models = [];
      if (isLMStudio) {
        try {
          const nativeRes = await axios_default.get(`${ollamaBase}/api/v0/models`, { timeout: 3e3 });
          const items = nativeRes.data?.data || [];
          if (items.length > 0) {
            models = items.filter((m) => m.state === "loaded" && (!m.type || m.type === "llm" || m.type === "vlm")).map((m) => m.id);
          }
        } catch {
        }
        if (models.length === 0) {
          const res = await axios_default.get(`${ollamaBase}/v1/models`, { timeout: 3e3 });
          models = (res.data?.data || []).map((m) => m.id);
        }
      } else {
        const res = await axios_default.get(`${ollamaBase}/api/tags`, { timeout: 3e3 });
        models = (res.data?.models || []).map((m) => m.name);
      }
      if (models.length === 0) {
        models = [defaultModel];
      } else if (!models.includes(defaultModel)) {
        models.unshift(defaultModel);
      }
      this._view.webview.postMessage({ type: "modelsList", value: models });
    } catch {
      this._view.webview.postMessage({ type: "modelsList", value: [defaultModel] });
    }
  }
