  '\u{1F4C2} \uD504\uB85C\uC81D\uD2B8 \uD30C\uC77C \uC0B4\uD3B4\uBCF4\uB294 \uC911...',
  '\u{1F9E0} \uAD00\uB828 \uC815\uBCF4 \uBAA8\uC73C\uB294 \uC911...',
