    +   '<div class="boot-sub">\uD68C\uC0AC \uD3F4\uB354 = \uC81C2\uC758 \uB450\uB1CC\uC785\uB2C8\uB2E4. \uC9C0\uC2DD\xB7\uBA54\uBAA8\uB9AC\xB7\uC5D0\uC774\uC804\uD2B8 \uC0B0\uCD9C\uBB3C\xB7\uC758\uC0AC\uACB0\uC815 \uB85C\uADF8\uAC00 \uBAA8\uB450 \uD55C \uACF3\uC5D0 \uC313\uC774\uACE0, GitHub\uB85C \uBC31\uC5C5\uD558\uBA74 \uB2E4\uB978 PC\uC5D0\uC11C\uB3C4 \uADF8\uB300\uB85C \uC774\uC5B4\uAC08 \uC218 \uC788\uC5B4\uC694.</div>'
    + '</div>'
    + '<div class="boot-body">'
    +   '<div class="boot-options">'
    +     '<button class="boot-opt recommended" data-choice="default">'
    +       '<span class="bo-icon">\u{1F3E0}</span>'
    +       '<span class="bo-text"><span class="bo-title">\uAE30\uC874 \uB450\uB1CC \uD3F4\uB354 \uADF8\uB300\uB85C \uC0AC\uC6A9 <span class="bo-recpill">\uAD8C\uC7A5</span></span><span class="bo-desc">~/.connect-ai-brain/ \uC548\uC5D0 _shared, _agents, sessions\uAC00 \uB9CC\uB4E4\uC5B4\uC9D1\uB2C8\uB2E4.</span></span>'
    +       '<span class="bo-arrow">\u2192</span>'
