    +     '<button class="boot-opt" data-choice="pick">'
    +       '<span class="bo-icon">\u{1F4C2}</span>'
    +       '<span class="bo-text"><span class="bo-title">\uB450\uB1CC \uC704\uCE58 \uC9C1\uC811 \uC120\uD0DD</span><span class="bo-desc">Dropbox\xB7iCloud \uB4F1 \uB2E4\uB978 \uC704\uCE58\uB85C \uB450\uB1CC \uC790\uCCB4\uB97C \uC62E\uAE41\uB2C8\uB2E4.</span></span>'
    +       '<span class="bo-arrow">\u2192</span>'
    +     '</button>'
    +     '<button class="boot-opt" data-choice="import">'
    +       '<span class="bo-icon">\u{1F4E5}</span>'
    +       '<span class="bo-text"><span class="bo-title">\uB2E4\uB978 PC\uC5D0\uC11C \uAC00\uC838\uC624\uAE30</span><span class="bo-desc">\uAE30\uC874 \uB450\uB1CC\uC758 GitHub URL\uB85C \uBCF5\uC6D0\uD569\uB2C8\uB2E4.</span></span>'
    +       '<span class="bo-arrow">\u2192</span>'
    +     '</button>'
    +   '</div>'
    + '</div>'
    + '<div class="boot-foot"><span class="boot-foot-hint">ESC = \uB098\uC911\uC5D0</span><span class="boot-spacer"></span></div>'
